from collections import Counter
from typing import List

MOD = 10**9 + 7

class Solution:
    def countSubMultisets(self, nums: List[int], l: int, r: int) -> int:
        count = Counter(nums)
        max_sum = r
        dp = [0] * (max_sum + 1)
        dp[0] = 1  # empty subset

        for num, freq in count.items():
            temp = dp[:]
            for s in range(max_sum + 1):
                if dp[s]:
                    for k in range(1, freq + 1):
                        next_s = s + k * num
                        if next_s > max_sum:
                            break
                        temp[next_s] = (temp[next_s] + dp[s]) % MOD
            dp = temp

        result = 0
        for s in range(l, r + 1):
            result = (result + dp[s]) % MOD
        return result
